cat > /tmp/boot_alpine.exp << 'EOF'
#!/usr/bin/expect -f

set timeout 60

# Start QEMU in background
spawn qemu-system-x86_64 -m 512 -cdrom /app/alpine.iso -boot d -serial telnet:127.0.0.1:6665,server,nowait -nographic

# Wait for boot loader prompt
expect {
    "boot:" {
        # Send boot command with serial console
        send "console=ttyS0,115200\r"
    }
    timeout {
        puts "Timeout waiting for boot prompt"
        exit 1
    }
}

# Wait for login prompt
expect {
    "login:" {
        puts "\nLogin prompt detected. Alpine is ready.\n"
        interact
    }
    timeout {
        puts "Timeout waiting for login prompt"
        interact
    }
}
EOF

cat > /tmp/boot_qemu.exp << 'EOFEXP'
#!/usr/bin/expect -f

set timeout 120

# Start QEMU with serial console
spawn qemu-system-x86_64 -m 512 -cdrom /app/alpine.iso -boot d -serial telnet:127.0.0.1:6665,server,nowait -nographic

# The -nographic option makes QEMU redirect VGA to stdio
# Syslinux should appear here

expect {
    -re "boot:.*" {
        send "\r"
        exp_continue
    }
    -re "login:" {
        puts "\n=== Login prompt detected ==="
        puts "System is ready. Keeping QEMU running...\n"
        # Detach from expect but keep process running
        interact
    }
    timeout {
        puts "\nTimeout - but QEMU should still be running"
        interact
    }
}
EOFEXP

